    en: { title: "EU intra-community VAT on B2B services: clear 2026 guide", excerpt: "When the reverse charge applies, what Form 349 reports, how a Spanish autonomo invoices a German or Irish company, and what changes with a non-EU client. Plain-language guide for B2B services.", metaTitle: "EU intra-community VAT B2B services 2026 guide", metaDescription: "Reverse charge mechanism, Form 349, VIES, invoicing without VAT to EU companies and common mistakes. Practical 2026 guide for autonomos and Spanish SLs.", keywords: ["EU intra-community VAT", "Form 349 Spain", "reverse charge VAT", "VIES ROI VAT", "invoice without VAT EU"] },
