    en: { title: "Spain IRPF withholding on invoices: when, how much and Forms 111/115/130", excerpt: "When you apply 7% or 15% on the invoice, what your client does with that withholding, how it links to Form 130 and to Forms 111 and 115 filed by the payer. Clear guide with examples.", metaTitle: "Spain IRPF withholding on invoices 2026 explained", metaDescription: "How IRPF withholding works on autonomos' invoices: 7% for new autonomos, 15% general, Form 130, Forms 111 and 115 by payer and common mistakes.", keywords: ["IRPF withholding Spain invoice", "15% IRPF withholding", "Form 111 Spain", "Form 115 Spain", "Form 130 autonomo"] },
