    es: { title: "Facturar sin ser autónomo en 2026: alternativas legales reales", excerpt: "Cooperativas de trabajo, recibos esporádicos, contratos mercantiles, holdings personales y la LLC americana. Repaso honesto a cada vía para emitir facturas sin pagar la cuota mensual de autónomo, con sus condiciones y riesgos.", metaTitle: "Facturar sin ser autónomo 2026: alternativas legales", metaDescription: "Cómo facturar sin darte de alta como autónomo en 2026 en España: cooperativas de facturación, ingresos esporádicos, contrato mercantil y LLC americana.", keywords: ["facturar sin ser autonomo", "cooperativa de facturacion 2026", "ingresos esporadicos sin autonomo", "alternativa autonomo Espana", "LLC para no autonomo"] },
    en: { title: "Invoicing without being self-employed in Spain 2026: real legal alternatives", excerpt: "Worker cooperatives, sporadic receipts, commercial contracts, personal holdings and the US LLC. Honest review of each route to issue invoices without paying the monthly autonomo quota, with conditions and risks.", metaTitle: "Invoice without autonomo Spain 2026: legal options", metaDescription: "How to invoice without registering as autonomo in Spain in 2026: invoicing cooperatives, sporadic income, commercial contract and US LLC.", keywords: ["invoice without being autonomo", "Spanish invoicing cooperative 2026", "sporadic income without autonomo", "Spain autonomo alternative", "LLC no autonomo"] },
    fr: { title: "Facturer sans être autonomo en Espagne 2026 : alternatives légales réelles", excerpt: "Coopératives de travail, recettes sporadiques, contrats commerciaux, holdings personnels et LLC américaine. Examen honnête de chaque voie pour émettre des factures sans payer la cotisation mensuelle d'autonomo, avec conditions et risques.", metaTitle: "Facturer sans autonomo Espagne 2026 : options légales", metaDescription: "Comment facturer sans vous inscrire comme autonomo en Espagne 2026 : coopératives de facturation, revenus sporadiques, contrat commercial et LLC américaine.", keywords: ["facturer sans etre autonomo", "cooperative de facturation 2026", "revenus sporadiques sans autonomo", "alternative autonomo Espagne", "LLC pour non autonomo"] },
    de: { title: "Rechnungen ohne Autonomo-Status in Spanien 2026: echte legale Alternativen", excerpt: "Arbeitsgenossenschaften, sporadische Quittungen, Werkverträge, persönliche Holdings und die US-LLC. Ehrlicher Überblick über jeden Weg, um Rechnungen zu stellen, ohne die monatliche Autonomo-Beitragsrate zu zahlen, mit Bedingungen und Risiken.", metaTitle: "Rechnung ohne Autonomo Spanien 2026: legale Optionen", metaDescription: "Wie Sie in Spanien 2026 Rechnungen stellen, ohne sich als Autonomo anzumelden: Rechnungsgenossenschaften, sporadische Einkünfte, Werkvertrag und US-LLC.", keywords: ["Rechnung ohne autonomo", "Rechnungsgenossenschaft 2026", "sporadische Einkunfte ohne autonomo", "Alternative autonomo Spanien", "LLC fur nicht autonomo"] },
    pt: { title: "Faturar sem ser autónomo em Espanha 2026: alternativas legais reais", excerpt: "Cooperativas de trabalho, recibos esporádicos, contratos mercantis, holdings pessoais e a LLC americana. Análise honesta de cada via para emitir faturas sem pagar a quota mensal de autónomo, com as suas condições e riscos.", metaTitle: "Faturar sem autónomo Espanha 2026: opções legais", metaDescription: "Como faturar sem se inscrever como autónomo em Espanha em 2026: cooperativas de faturação, rendimentos esporádicos, contrato mercantil e LLC americana.", keywords: ["faturar sem ser autonomo", "cooperativa de faturacao 2026", "rendimentos esporadicos sem autonomo", "alternativa autonomo Espanha", "LLC para nao autonomo"] },
    ca: { title: "Facturar sense ser autònom el 2026: alternatives legals reals", excerpt: "Cooperatives de treball, rebuts esporàdics, contractes mercantils, holdings personals i la LLC americana. Repàs honest a cada via per emetre factures sense pagar la quota mensual d'autònom, amb les seves condicions i riscos.", metaTitle: "Facturar sense ser autònom 2026: alternatives legals", metaDescription: "Com facturar sense donar-te d'alta com a autònom el 2026 a Espanya: cooperatives de facturació, ingressos esporàdics, contracte mercantil i LLC americana.", keywords: ["facturar sense ser autonom", "cooperativa de facturacio 2026", "ingressos esporadics sense autonom", "alternativa autonom Espanya", "LLC per a no autonom"] },
